  ('real-estate-moex-02412', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '重新實施地籍測量之結果，應予公告三十日，逾公告期間未經聲請複丈，或複丈結果無誤或經更正者，地政機關應即據以辦理 何種登記？', '["土地所有權變更登記", "土地標示變更登記", "土地權利信託登記", "共有型態變更登記"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02413', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地法規定，土地權利關係人，在公告期間內，如有異議，得向該管直轄市或縣（市）地政機關以書面提出，並應附具證明 文件。該管直轄市或縣（市）地政機關應依下列何種方式處理？', '["調處", "調解", "仲裁", "起訴"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02414', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地總登記，謂於一定期間內就直轄市或縣（市）土地之全部為土地登記。依土地法規定，土地總登記，土地所有權人應按下 列何者繳納登記費千分之二？', '["公告現值", "公告地價", "法定地價", "申報地價"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02415', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地法規定，登記儲金專備因登記錯誤、遺漏或虛偽致受損害者，作為地政機關負損害賠償之用。地政機關應提存所收登記 費多少比率作為登記儲金？', '["百分之一", "百分之五", "百分之十", "百分之十五"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02416', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地登記錯誤、遺漏或虛偽致受損害者，損害賠償之請求，如經地政機關拒絕，依土地法規定，受損害人得依下列何種方式處 理？', '["向司法機關起訴", "向該管直轄市或縣（市）政府申請調處", "向鄉、鎮、市調解委員會申請調解", "向地政機關申請仲裁"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02417', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地權利變更登記，應由權利人及義務人會同聲請之。其無義務人者，由權利人聲請之。以贈與為登記原因，聲請土地權利變 更登記，依土地法規定，應於權利變更之日起多久期間內為之？', '["一個月", "二個月", "三個月", "六個月 （請接背面） 98年專門職業及技術人員高等考試建築師、技師、消 全一張 防設備師考試、普通考試不動產經紀人、記帳士、第 代號：60140 （背面） 二次消防設備士考試暨特種考試語言治療師考試試題 等    別 ：普通考試 類    科 ：不動產經紀人 科    目 ：土地法與土地相關稅法概要"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02418', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列各種不同種類之登記原因，何者係限制登記名義人處分其土地權利所為之登記？', '["更正", "更名", "查封", "清償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
