  ('real-estate-moex-02420', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '預告登記未塗銷前，登記名義人就其土地所為之處分，對於所登記之請求權有妨礙者無效。但預告登記對於下列何種情形而為 新登記者，無排除之效力？', '["買賣", "強制執行", "贈與", "交換"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02421', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於土地增值稅之減徵規定，下列何者錯誤？', '["經重劃之土地，於重劃後第一次移轉時，其土地增值稅減徵40%", "區段徵收之土地，領回抵價地後第一次移轉時，其土地增值稅減徵40%", "作農業使用之農業用地，移轉與自然人時，其土地增值稅減徵40%", "都市更新地區依權利變換取得之土地，於更新後第一次移轉時，減徵土地增值稅40%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
